+    );
+
+    // Cancellation case
+    let ctx = ExecutionContext::request_scoped(Duration::from_secs(10));
+    ctx.cancel();
+    let result = ctx
+        .run(async { time::sleep(Duration::from_secs(60)).await })
+        .await;
